const { alerts, recurringItems, targetMonth, targetYear } = $json;
let html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden"><div style="background:linear-gradient(135deg,#0D1B2A,#1a3a5c);padding:24px 28px"><p style="margin:0 0 4px;color:#90e0ef;font-size:11px;letter-spacing:2px">FINSMART AI</p><h1 style="margin:0;color:#fff;font-size:20px;font-weight:800">Budget Alert</h1><p style="margin:4px 0 0;color:#94a3b8;font-size:13px">${targetMonth} ${targetYear}</p></div><div style="padding:24px 28px">`;
for (const a of alerts) {
  const isOver = a.level === 'OVER';
  html += `<div style="background:${isOver?'#fee2e2':'#fef3c7'};border:1px solid ${isOver?'#fca5a5':'#fde68a'};border-radius:8px;padding:14px 16px;margin-bottom:10px"><p style="margin:0;font-size:14px;color:${isOver?'#991b1b':'#92400e'};font-weight:700">${isOver?'🔴':'⚠️'} ${a.cat}</p><p style="margin:4px 0 0;font-size:13px;color:${isOver?'#7f1d1d':'#78350f'}">₹${a.spent.toLocaleString()} of ₹${a.budget.toLocaleString()} budget (${a.pct}%)</p></div>`;
}
if (recurringItems && recurringItems.length > 0) {
  html += `<div style="margin-top:16px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:8px;padding:14px 16px"><p style="margin:0 0 8px;font-size:14px;color:#0369a1;font-weight:700">🔄 Recurring Expenses</p>${recurringItems.slice(0,3).map(r => `<p style="margin:0 0 4px;font-size:13px;color:#0c4a6e">• <b>${r.desc}</b> — ${r.count}x = ₹${r.total.toLocaleString()}</p>`).join('')}</div>`;
}
html += `</div><div style="background:#0D1B2A;padding:14px 28px;text-align:center"><p style="margin:0;color:#475569;font-size:11px">FinSmart AI • ${targetMonth} ${targetYear}</p></div></div>`;
return [{ json: { ...($json), alertEmailHtml: html } }];

const BUDGETS = {
  Food: 3000, Transport: 1500, Housing: 5000,
  Entertainment: 1000, Health: 2000, Education: 2000,
  Shopping: 2000, Utilities: 1500, Other: 1000
};

const COL_MONTH = 'Month', COL_YEAR = 'Year', COL_CAT = 'Category', COL_AMT = 'Amount (₹)';
const MONTH_ORDER = ['January','February','March','April','May','June','July','August','September','October','November','December'];

const allRows = $input.all().map(i => i.json).filter(r => r[COL_AMT] && r[COL_MONTH]);

const combos = [...new Set(allRows.map(r => `${String(r[COL_MONTH] || '').trim()}||${r[COL_YEAR]}`))]
  .map(c => { const [m, y] = c.split('||'); return { month: m, year: parseInt(y) }; })
  .sort((a, b) => a.year !== b.year ? b.year - a.year : MONTH_ORDER.indexOf(b.month) - MONTH_ORDER.indexOf(a.month));

const targetMonth = combos[0]?.month || '';
const targetYear  = combos[0]?.year  || 2026;

const monthRows = allRows.filter(r =>
  String(r[COL_MONTH] || '').trim() === targetMonth && parseInt(r[COL_YEAR]) === targetYear
);

const catSpend = {};
for (const row of monthRows) {
  const cat = String(row[COL_CAT] || 'Other').trim();
  catSpend[cat] = (catSpend[cat] || 0) + (parseFloat(row[COL_AMT]) || 0);
}

const totalSpent  = Object.values(catSpend).reduce((s, v) => s + v, 0);
const totalBudget = Object.values(BUDGETS).reduce((s, v) => s + v, 0);
const overallPct  = totalBudget > 0 ? Math.round(totalSpent / totalBudget * 100) : 0;

const alerts = [];
for (const [cat, budget] of Object.entries(BUDGETS)) {
  const spent = catSpend[cat] || 0;
  const pct   = budget > 0 ? (spent / budget * 100) : 0;
  if (pct >= 80) alerts.push({ cat, spent: Math.round(spent), budget, pct: Math.round(pct), level: pct >= 100 ? 'OVER' : 'WARNING' });
}

const sc = overallPct >= 100 ? '#dc2626' : overallPct >= 80 ? '#d97706' : '#16a34a';
const sb = overallPct >= 100 ? '#fee2e2' : overallPct >= 80 ? '#fef3c7' : '#dcfce7';

let catRows = '';
for (const [cat, budget] of Object.entries(BUDGETS)) {
  const spent = catSpend[cat] || 0;
  const pct   = budget > 0 ? Math.round(spent / budget * 100) : 0;
  const bar   = Math.min(pct, 100);
  const col   = pct >= 100 ? '#dc2626' : pct >= 80 ? '#f59e0b' : '#00B4D8';
  catRows += `<tr>
    <td style="padding:8px 12px;font-size:13px;color:#1e293b">${cat}</td>
    <td style="padding:8px 12px;font-size:13px;font-weight:700">₹${Math.round(spent).toLocaleString()}</td>
    <td style="padding:8px 12px;font-size:13px;color:#64748b">₹${budget.toLocaleString()}</td>
    <td style="padding:8px 12px">
      <div style="background:#e2e8f0;border-radius:4px;height:8px;width:100px">
        <div style="background:${col};width:${bar}%;height:8px;border-radius:4px"></div>
      </div>
    </td>
    <td style="padding:8px 12px;font-size:13px;font-weight:700;color:${col}">${pct}%</td>
  </tr>`;
}

const alertsHtml = alerts.length > 0
  ? `<div style="margin-top:16px;background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:14px 16px">
      <p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#9a3412">⚠️ Alerts</p>
      ${alerts.map(a => `<p style="margin:0 0 4px;font-size:13px;color:#7c2d12">${a.level === 'OVER' ? '🔴' : '🟡'} <b>${a.cat}</b>: ${a.pct}% used</p>`).join('')}
    </div>`
  : `<div style="margin-top:16px;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:14px 16px">
      <p style="margin:0;font-size:13px;color:#166534">✅ All categories within budget!</p>
    </div>`;

const html = `
<div style="font-family:Arial,sans-serif;max-width:650px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden">
  <div style="background:linear-gradient(135deg,#0D1B2A,#1a3a5c);padding:24px 28px">
    <p style="margin:0 0 4px;color:#90e0ef;font-size:11px;letter-spacing:2px">FINSMART AI • DAILY SUMMARY</p>
    <h1 style="margin:0;color:#fff;font-size:20px;font-weight:800">${targetMonth} ${targetYear}</h1>
    <p style="margin:6px 0 0;color:#94a3b8;font-size:13px">${monthRows.length} transactions logged</p>
  </div>
  <div style="padding:20px 28px">
    <div style="background:${sb};border-radius:10px;padding:16px 20px;margin-bottom:20px">
      <p style="margin:0 0 2px;font-size:12px;color:#64748b;text-transform:uppercase">Total Spent</p>
      <p style="margin:0;font-size:26px;font-weight:800;color:${sc}">
        ₹${Math.round(totalSpent).toLocaleString()}
        <span style="font-size:14px;font-weight:400">of ₹${totalBudget.toLocaleString()} (${overallPct}%)</span>
      </p>
    </div>
    <h3 style="margin:0 0 10px;font-size:13px;font-weight:800;color:#0D1B2A;text-transform:uppercase">Category Breakdown</h3>
    <table width="100%" cellpadding="0" cellspacing="0" style="border-radius:8px;overflow:hidden;border:1px solid #e2e8f0">
      <thead>
        <tr style="background:#0D1B2A">
          <th style="padding:8px 12px;text-align:left;color:#90e0ef;font-size:11px">Category</th>
          <th style="padding:8px 12px;text-align:left;color:#90e0ef;font-size:11px">Spent</th>
          <th style="padding:8px 12px;text-align:left;color:#90e0ef;font-size:11px">Budget</th>
          <th style="padding:8px 12px;text-align:left;color:#90e0ef;font-size:11px">Progress</th>
          <th style="padding:8px 12px;text-align:left;color:#90e0ef;font-size:11px">%</th>
        </tr>
      </thead>
      <tbody>${catRows}</tbody>
    </table>
    ${alertsHtml}
  </div>
  <div style="background:#0D1B2A;padding:14px 28px;text-align:center">
    <p style="margin:0;color:#475569;font-size:11px">FinSmart AI • ${targetMonth} ${targetYear}</p>
  </div>
</div>`;

return [{ json: { dailyEmailHtml: html, targetMonth, targetYear, totalSpent: Math.round(totalSpent), overallPct } }];

const date = new Date($node['On form submission2'].json['Date']);
const aiOutput = JSON.parse($node['Basic LLM Chain2'].json.text);

return [{
  json: {
    date: date.getDate(),
    year: aiOutput.year,
    month: date.toLocaleString('en-US', { month: 'long' }),
    amount: $node['On form submission2'].json['Amount (₹)'],
    description: $node['On form submission2'].json['Description'],
    payment_mode: $node['On form submission2'].json['Payment Mode'],
    category: aiOutput.category,
    suggestion: aiOutput.suggestion,
    week: aiOutput.week
  }
}];

// ── BUDGET ALERT CHECK ──────────────────────────────────────
// Reads all rows and checks if current month spending in any
// category has crossed 80% or 100% of the configured budget.
// Edit BUDGETS below to match your monthly limits.

const BUDGETS = {
  Food: 10000,
  Transport: 10000,
  Housing: 10000,
  Entertainment: 10000,
  Health: 10000,
  Education: 10000,
  Shopping: 10000,
  Utilities: 10000,
  Other: 10000
};

const COL_MONTH = 'Month';
const COL_YEAR  = 'Year';
const COL_CAT   = 'Category';
const COL_AMT   = 'Amount (\u20b9)';
const COL_DESC  = 'Description';
const COL_SUB   = 'Submitted By';

const allRows = $input.all().map(i => i.json).filter(r => r[COL_AMT] && r[COL_MONTH]);

const MONTH_ORDER = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const combos = [...new Set(allRows.map(r => `${(r[COL_MONTH]||'').trim()}||${r[COL_YEAR]}`))]
  .map(c => { const [m,y] = c.split('||'); return { month: m, year: parseInt(y) }; })
  .sort((a, b) => a.year !== b.year ? b.year - a.year : MONTH_ORDER.indexOf(b.month) - MONTH_ORDER.indexOf(a.month));

const targetMonth = combos[0]?.month || 'April';
const targetYear  = combos[0]?.year  || 2026;

const monthRows = allRows.filter(r =>
  (r[COL_MONTH]||'').trim() === targetMonth && parseInt(r[COL_YEAR]) === targetYear
);

// Spending per category this month
const catSpend = {};
for (const row of monthRows) {
  const cat = (row[COL_CAT] || 'Other').trim();
  catSpend[cat] = (catSpend[cat] || 0) + (parseFloat(row[COL_AMT]) || 0);
}

// Recurring expense detection (same description 3+ times)
const descCount = {};
for (const row of monthRows) {
  const d = (row[COL_DESC] || '').trim().toLowerCase();
  if (d) descCount[d] = (descCount[d] || 0) + 1;
}
const recurringItems = Object.entries(descCount)
  .filter(([, c]) => c >= 3)
  .map(([desc, count]) => {
    const total = monthRows
      .filter(r => (r[COL_DESC]||'').trim().toLowerCase() === desc)
      .reduce((s, r) => s + (parseFloat(r[COL_AMT]) || 0), 0);
    return { desc, count, total: Math.round(total) };
  });

// Budget alerts
const alerts = [];
for (const [cat, budget] of Object.entries(BUDGETS)) {
  const spent = catSpend[cat] || 0;
  const pct = budget > 0 ? (spent / budget * 100) : 0;
  if (pct >= 100) {
    alerts.push({ cat, spent: Math.round(spent), budget, pct: Math.round(pct), level: 'OVER' });
  } else if (pct >= 80) {
    alerts.push({ cat, spent: Math.round(spent), budget, pct: Math.round(pct), level: 'WARNING' });
  }
}

// Per-member totals
const memberMap = {};
for (const row of monthRows) {
  const member = (row[COL_SUB] || 'Unknown').trim();
  memberMap[member] = (memberMap[member] || 0) + (parseFloat(row[COL_AMT]) || 0);
}
const memberData = Object.entries(memberMap)
  .map(([name, amt]) => ({ name, amt: Math.round(amt) }))
  .sort((a, b) => b.amt - a.amt);

return [{ json: {
  targetMonth, targetYear,
  catSpend: Object.fromEntries(Object.entries(catSpend).map(([k,v]) => [k, Math.round(v)])),
  budgets: BUDGETS,
  alerts,
  recurringItems,
  memberData,
  allRows,
  monthRows
}}];

const BUDGETS = {
  Food: 3000, Transport: 1500, Housing: 5000,
  Entertainment: 1000, Health: 2000, Education: 2000,
  Shopping: 2000, Utilities: 1500, Other: 1000
};

const COL_MONTH = 'Month', COL_YEAR = 'Year', COL_CAT = 'Category';
const COL_DESC = 'Description', COL_AMT = 'Amount (₹)';
const COL_PAY = 'Payment Mode', COL_WEEK = 'Week (Month)';
const COL_AI = 'AI Suggestion', COL_SUB = 'Submitted By';

const MONTH_ORDER = ['January','February','March','April','May','June','July','August','September','October','November','December'];

const allRows = $input.all().map(i => i.json).filter(r => r[COL_AMT] && r[COL_MONTH]);

const combos = [...new Set(allRows.map(r => `${String(r[COL_MONTH]||'').trim()}||${r[COL_YEAR]}`))]
  .map(c => { const [m,y] = c.split('||'); return { month: m, year: parseInt(y) }; })
  .sort((a, b) => a.year !== b.year ? b.year - a.year : MONTH_ORDER.indexOf(b.month) - MONTH_ORDER.indexOf(a.month));

const targetMonth = combos[0]?.month || 'April';
const targetYear  = combos[0]?.year  || 2026;
const prevCombo   = combos[1];
const reportPeriod = `${targetMonth} ${targetYear}`;

const monthRows = allRows.filter(r =>
  String(r[COL_MONTH]||'').trim() === targetMonth && parseInt(r[COL_YEAR]) === targetYear
);
const prevRows = prevCombo ? allRows.filter(r =>
  String(r[COL_MONTH]||'').trim() === prevCombo.month && parseInt(r[COL_YEAR]) === prevCombo.year
) : [];

// ── Core KPIs ────────────────────────────────────────────────
const totalSpent    = monthRows.reduce((s, r) => s + (parseFloat(r[COL_AMT]) || 0), 0);
const prevTotal     = prevRows.reduce((s, r) => s + (parseFloat(r[COL_AMT]) || 0), 0);
const txCount       = monthRows.length;
const avgTxn        = txCount > 0 ? totalSpent / txCount : 0;
const momChange     = prevTotal > 0 ? ((totalSpent - prevTotal) / prevTotal * 100).toFixed(1) : null;

const biggest = monthRows.reduce((max, r) => {
  const a = parseFloat(r[COL_AMT]) || 0;
  return a > max.amt ? { amt: a, desc: String(r[COL_DESC]||'-'), cat: String(r[COL_CAT]||'-') } : max;
}, { amt: 0, desc: '-', cat: '-' });

// ── Category analysis with budget comparison ─────────────────
const catMap = {}, catTxCount = {}, prevCatMap = {};
for (const row of monthRows) {
  const cat = String(row[COL_CAT] || 'Other').trim();
  catMap[cat]     = (catMap[cat]     || 0) + (parseFloat(row[COL_AMT]) || 0);
  catTxCount[cat] = (catTxCount[cat] || 0) + 1;
}
for (const row of prevRows) {
  const cat = String(row[COL_CAT] || 'Other').trim();
  prevCatMap[cat] = (prevCatMap[cat] || 0) + (parseFloat(row[COL_AMT]) || 0);
}

const catData = Object.entries(catMap).map(([name, spent]) => {
  const budget = BUDGETS[name] || 0;
  const pct    = totalSpent > 0 ? (spent / totalSpent * 100).toFixed(1) : '0.0';
  const budgetPct = budget > 0 ? Math.min(Math.round(spent / budget * 100), 100) : 0;
  const budgetStatus = budget === 0 ? 'N/A' : spent > budget ? 'OVER' : spent / budget >= 0.8 ? 'WARNING' : 'OK';
  const prevSpent = prevCatMap[name] || 0;
  const momDelta  = prevSpent > 0 ? ((spent - prevSpent) / prevSpent * 100).toFixed(0) : null;
  return { name, spent: Math.round(spent), txns: catTxCount[name] || 0, pct, budget, budgetPct, budgetStatus, momDelta };
}).sort((a, b) => b.spent - a.spent);

const topCategory   = catData[0]?.name || '—';
const totalBudget   = Object.values(BUDGETS).reduce((s, v) => s + v, 0);
const budgetUsedPct = totalBudget > 0 ? Math.round(totalSpent / totalBudget * 100) : 0;

// ── Payment Mode ─────────────────────────────────────────────
const payMap = {};
for (const row of monthRows) {
  const mode = String(row[COL_PAY] || 'Other').trim();
  payMap[mode] = (payMap[mode] || 0) + (parseFloat(row[COL_AMT]) || 0);
}
const payData = Object.entries(payMap)
  .map(([mode, amt]) => ({ mode, amt: Math.round(amt), pct: totalSpent > 0 ? (amt / totalSpent * 100).toFixed(1) : '0.0' }))
  .sort((a, b) => b.amt - a.amt);

// ── Weekly breakdown ─────────────────────────────────────────
const weekMap = {};
for (const row of monthRows) {
  const wk = row[COL_WEEK] ? `Week ${row[COL_WEEK]}` : 'Unknown';
  weekMap[wk] = (weekMap[wk] || 0) + (parseFloat(row[COL_AMT]) || 0);
}
const weekData = Object.entries(weekMap)
  .map(([wk, amt]) => ({ wk, amt: Math.round(amt) }))
  .sort((a, b) => a.wk.localeCompare(b.wk));

// ── Recurring expenses ────────────────────────────────────────
const descCount = {};
for (const row of monthRows) {
  const d = String(row[COL_DESC] || '').trim().toLowerCase();
  if (d) descCount[d] = (descCount[d] || 0) + 1;
}
const recurringItems = Object.entries(descCount)
  .filter(([, c]) => c >= 3)
  .map(([desc, count]) => {
    const total = monthRows
      .filter(r => String(r[COL_DESC]||'').trim().toLowerCase() === desc)
      .reduce((s, r) => s + (parseFloat(r[COL_AMT]) || 0), 0);
    return { desc, count, total: Math.round(total) };
  })
  .sort((a, b) => b.total - a.total);

// ── Per-member totals ────────────────────────────────────────
const memberMap = {};
for (const row of monthRows) {
  const member = String(row[COL_SUB] || 'Unknown').trim();
  memberMap[member] = (memberMap[member] || 0) + (parseFloat(row[COL_AMT]) || 0);
}
const memberData = Object.entries(memberMap)
  .map(([name, amt]) => ({ name, amt: Math.round(amt), pct: totalSpent > 0 ? (amt / totalSpent * 100).toFixed(1) : '0.0' }))
  .sort((a, b) => b.amt - a.amt);

// ── AI Suggestions ───────────────────────────────────────────
const aiSuggestions = [...new Set(
  monthRows.map(r => String(r[COL_AI] || '').trim()).filter(s => s && s !== '#N/A' && s.length > 3)
)];

// ── All transactions ─────────────────────────────────────────
const allTx = [...monthRows].sort((a, b) => (a[COL_WEEK]||0) - (b[COL_WEEK]||0));

// ══════════════════════════════════════════════════════════════
// BUILD HTML REPORT
// ══════════════════════════════════════════════════════════════
const CAT_COLORS = {
  Food:'#00B4D8', Transport:'#F4A261', Housing:'#2EC4B6',
  Entertainment:'#E63946', Health:'#7B2FBE', Education:'#F77F00',
  Shopping:'#4CC9F0', Utilities:'#06D6A0', Other:'#94A3B8'
};
const PAY_COLORS = { Cash:'#2EC4B6', Card:'#00B4D8', UPI:'#F4A261', 'Net Banking':'#7B2FBE', Other:'#94A3B8' };
const STATUS_STYLE = { OK: 'color:#166534;background:#dcfce7', WARNING: 'color:#92400e;background:#fef3c7', OVER: 'color:#991b1b;background:#fee2e2', 'N/A': 'color:#94a3b8;background:#f1f5f9' };
const STATUS_ICON  = { OK: '✅', WARNING: '⚠️', OVER: '🔴', 'N/A': '—' };

const momBadge = momChange !== null
  ? `<span style="font-size:12px;padding:2px 8px;border-radius:12px;${parseFloat(momChange) <= 0 ? 'background:#dcfce7;color:#166534' : 'background:#fee2e2;color:#991b1b'}">${parseFloat(momChange) > 0 ? '▲' : '▼'} ${Math.abs(momChange)}% vs ${prevCombo?.month}</span>`
  : '';

const budgetBadge = `<span style="font-size:12px;padding:2px 8px;border-radius:12px;${budgetUsedPct >= 100 ? 'background:#fee2e2;color:#991b1b' : budgetUsedPct >= 80 ? 'background:#fef3c7;color:#92400e' : 'background:#dcfce7;color:#166534'}">${budgetUsedPct}% of total budget</span>`;

const catRows = catData.map((c, i) => {
  const col = CAT_COLORS[c.name] || '#94A3B8';
  const bg  = i % 2 === 0 ? '#ffffff' : '#f8fafc';
  const statusStyle = STATUS_STYLE[c.budgetStatus] || STATUS_STYLE['N/A'];
  const statusIcon  = STATUS_ICON[c.budgetStatus]  || '—';
  const momArrow = c.momDelta !== null
    ? (parseFloat(c.momDelta) > 0
      ? `<span style="color:#dc2626;font-size:11px">▲${c.momDelta}%</span>`
      : `<span style="color:#16a34a;font-size:11px">▼${Math.abs(c.momDelta)}%</span>`)
    : '<span style="color:#94a3b8;font-size:11px">—</span>';
  return `<tr style="background:${bg}">
    <td style="padding:10px 12px;font-size:13px;color:#1e293b;font-weight:500"><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:${col};margin-right:7px"></span>${c.name}</td>
    <td style="padding:10px 12px;font-size:13px;font-weight:700;color:#0f172a">₹${c.spent.toLocaleString()}</td>
    <td style="padding:10px 12px;font-size:13px;color:#475569">${c.pct}%</td>
    <td style="padding:10px 12px;font-size:12px">
      <div style="display:flex;align-items:center;gap:6px">
        <div style="background:#e2e8f0;border-radius:4px;height:8px;width:90px;flex-shrink:0">
          <div style="background:${c.budgetStatus==='OVER'?'#dc2626':c.budgetStatus==='WARNING'?'#f59e0b':col};width:${c.budgetPct}%;height:8px;border-radius:4px"></div>
        </div>
        <span style="color:#64748b">${c.budget > 0 ? '₹'+c.budget.toLocaleString() : '—'}</span>
      </div>
    </td>
    <td style="padding:10px 12px;text-align:center"><span style="padding:2px 7px;border-radius:10px;font-size:11px;font-weight:600;${statusStyle}">${statusIcon} ${c.budgetStatus}</span></td>
    <td style="padding:10px 12px;text-align:center">${momArrow}</td>
    <td style="padding:10px 12px;font-size:12px;color:#64748b;text-align:center">${c.txns}</td>
  </tr>`;
}).join('');

const payRows = payData.map((p, i) => {
  const col = PAY_COLORS[p.mode] || '#94A3B8';
  const bg  = i % 2 === 0 ? '#ffffff' : '#f8fafc';
  return `<tr style="background:${bg}">
